import { Component, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormBuilder, Validators } from '@angular/forms';
import { RouterLink } from '@angular/router';

@Component({
  selector: 'app-condition-new',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterLink],
  templateUrl: './condition-new.component.html',
})
export class ConditionNewComponent {
  private fb = inject(FormBuilder);

  form = this.fb.group({
    loggedOn: ['2026-07-12T05:30', [Validators.required]],
    waterTempC: [19, [Validators.required]],
    windKts: [8, [Validators.required, Validators.min(0)]],
    note: [''],
  });

  submit(): void {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
    }
    // service_agent wires this to ApiService.createCondition.
  }
}
